import React, { useState } from 'react';

const Contact = () => {
  const [status, setStatus] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    setStatus('Message sent successfully! We will get back to you soon.');
    e.target.reset();
    setTimeout(() => setStatus(''), 5000);
  };

  return (
    <div className="page-container">
      <div className="page-header">
        <h1>Contact Us</h1>
        <p>Have questions or want to partner with us? Reach out!</p>
      </div>

      <div className="contact-wrapper">
        <div className="contact-info">
          <div className="info-card">
            <h3>📍 Our Office</h3>
            <p>123 Innovation Drive<br/>Tech Park, Bangalore 560001</p>
          </div>
          <div className="info-card">
            <h3>📞 Phone</h3>
            <p>+91 98765 43210</p>
          </div>
          <div className="info-card">
            <h3>✉️ Email</h3>
            <p>hello@animalhelper.in</p>
          </div>
        </div>

        <form className="contact-form" onSubmit={handleSubmit}>
          {status && <div className="status-message">{status}</div>}

          <div className="form-group">
            <label htmlFor="name">Full Name</label>
            <input type="text" id="name" required placeholder="John Doe" />
          </div>

          <div className="form-group">
            <label htmlFor="email">Email Address</label>
            <input type="email" id="email" required placeholder="john@example.com" />
          </div>

          <div className="form-group">
            <label htmlFor="message">Your Message</label>
            <textarea id="message" required rows="5" placeholder="How can we help you?"></textarea>
          </div>

          <button type="submit" className="submit-btn">Send Message</button>
        </form>
      </div>
    </div>
  );
};

export default Contact;
